spiral-matrix.solution:
class Solution(object):
    def spiralOrder(self, matrix):
        """
        :type matrix: List[List[int]]
        :rtype: List[int]
        """
        if matrix == [] or matrix[0] == []: return []
        row_begin, row_end = 0, len(matrix)-1
        col_begin, col_end = 0, len(matrix[0])-1
        result = []

        while row_begin <= row_end and col_begin <= col_end:
            for i in range(col_begin, col_end+1):
                result.append(matrix[row_begin][i])
            row_begin += 1

            for i in range(row_begin, row_end+1):
                result.append(matrix[i][col_end])
            col_end -= 1

            if row_begin <= row_end:
                for i in range(col_end, col_begin-1, -1):
                    result.append(matrix[row_end][i])
            row_end -= 1

            if col_begin <= col_end:
                for i in range(row_end, row_begin-1, -1):
                    result.append(matrix[i][col_begin])
            col_begin += 1

        return result

summary-ranges.solution:
class Solution(object):
    def summaryRanges(self, nums):
        if not nums:
            return []

        ranges = []
        start = nums[0]

        for i in range(1, len(nums)):
            if nums[i] != nums[i-1] + 1:
                if start == nums[i-1]:
                    ranges.append(str(start))
                else:
                    ranges.append(str(start) + "->" + str(nums[i-1]))
                start = nums[i]

        if start == nums[-1]:
            ranges.append(str(start))
        else:
            ranges.append(str(start) + "->" + str(nums[-1]))

        return ranges

distinct-subsequences.solution:
class Solution(object):
    def numDistinct(self, s, t):
        """
        :type s: str
        :type t: str
        :rtype: int
        """

        m, n = len(s), len(t)
        dp = [[0] * (n+1) for _ in range(m+1)]

        for i in range(m+1):
            dp[i][0] = 1

        for i in range(1, m+1):
            for j in range(1, n+1):
                if s[i-1] == t[j-1]:
                    dp[i][j] = dp[i-1][j-1] + dp[i-1][j]
                else:
                    dp[i][j] = dp[i-1][j]

        return dp[m][n]

first-missing-positive.solution:
class Solution(object):
    def firstMissingPositive(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """

        n = len(nums)

        # Put each number in its correct place
        for i in range(n):
            while 1 <= nums[i] <= n and nums[nums[i] - 1] != nums[i]:
                nums[nums[i] - 1], nums[i] = nums[i], nums[nums[i] - 1]

        # Find the first number not in its place
        for i in range(n):
            if nums[i] != i + 1:
                return i + 1

        # If all numbers are in their place, the missing number is n + 1
        return n + 1

