class Solution(object):
    def addOperators(self, num, target):
        def dfs(idx, path, value, last):
            if idx == len(num) and value == target:
                result.append(path)
                return
            for i in range(idx + 1, len(num) + 1):
                if i > idx + 1 and num[idx] == '0':
                    break
                cur = int(num[idx:i])
                if idx == 0:
                    dfs(i, path + num[idx:i], cur, cur)
                else:
                    dfs(i, path + '+' + num[idx:i], value + cur, cur)
                    dfs(i, path + '-' + num[idx:i], value - cur, -cur)
                    dfs(i, path + '*' + num[idx:i], value - last + last * cur, last * cur)

        result = []
        dfs(0, "", 0, 0)
        return result

