class Solution(object):
    def isMatch(self, s, p):
        """
        :type s: str
        :type p: str
        :rtype: bool
        """
        ls, lp = len(s), len(p)
        dp = [[False] * (ls + 1) for _ in range(lp + 1)]
        dp[0][0] = True

        for pi in range(1, lp + 1):
            if p[pi - 1] == '*':
                dp[pi][0] = dp[pi - 2][0]
            else:
                dp[pi][0] = False

        for si in range(1, ls + 1):
            for pi in range(1, lp + 1):
                if p[pi - 1] == '*':
                    dp[pi][si] = dp[pi - 2][si] or (dp[pi][si - 1] and (p[pi - 2] == s[si - 1] or p[pi - 2] == '.'))
                else:
                    dp[pi][si] = dp[pi - 1][si - 1] and (p[pi - 1] == s[si - 1] or p[pi - 1] == '.')

        return dp[lp][ls]

create-maximum-number.solution:
class Solution(object):
    def maxNumber(self, nums1, nums2, k):
        """
        :type nums1: List[int]
        :type nums2: List[int]
        :type k: int
        :rtype: List[int]
        """
        def pick_max(nums, k):
            drop = len(nums) - k
            stack = []
            for num in nums:
                while stack and drop and num > stack[-1]:
                    stack.pop()
                    drop -= 1
                stack.append(num)
            return stack[:k]

        def merge(A, B):
            ans = []
            while A or B:
                bigger = A if A > B else B
                ans.append(bigger[0])
                bigger.pop(0)
            return ans

        m, n = len(nums1), len(nums2)
        return max(merge(pick_max(nums1, i), pick_max(nums2, k-i)) for i in range(k+1) if i <= m and k-i <= n)

perfect-number.solution:
class Solution(object):
    def checkPerfectNumber(self, num):
        """
        :type num: int
        :rtype: bool
        """
        if num <= 1:
            return False
        sum_divisors = 1
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                sum_divisors += i
                if i != num // i:
                    sum_divisors += num // i
        return sum_divisors == num

