class Solution:
    def toHex(self, num: int) -> str:
        if num == 0:
            return '0'

        mp = '0123456789abcdef'
        ans = []
        for i in range(8):
            ans.append(mp[num & 15])
            num >>= 4

        return ''.join(ans[::-1])

