class Solution:
    def containsNearbyAlmostDuplicate(self, nums, indexDiff, valueDiff):
        if indexDiff < 1 or valueDiff < 0:
            return False

        num_dict = {}
        for i, num in enumerate(nums):
            bucket = num // (valueDiff + 1)

            if bucket in num_dict or (bucket - 1 in num_dict and num - num_dict[bucket - 1] <= valueDiff) or (bucket + 1 in num_dict and num_dict[bucket + 1] - num <= valueDiff):
                return True

            num_dict[bucket] = num

            if i >= indexDiff:
                del num_dict[nums[i - indexDiff] // (valueDiff + 1)]

        return False

