class Solution(object):
    def minSwapsCouples(self, row):
        """
        :type row: List[int]
        :rtype: int
        """
        def find(x):
            if p[x] != x:
                p[x] = find(p[x])
            return p[x]

        def union(x, y):
            p[find(x)] = find(y)

        n = len(row) // 2
        p = list(range(n))

        for i in range(0, len(row), 2):
            union(row[i] // 2, row[i + 1] // 2)

        return n - sum(find(i) == i for i in range(n))

