class Solution(object):
    def longestPalindrome(self, s):
        """
        :type s: str
        :rtype: int
        """

        counts = {}
        for char in s:
            if char in counts:
                counts[char] += 1
            else:
                counts[char] = 1

        length = 0
        odd_found = False
        for count in counts.values():
            if count % 2 == 0:
                length += count
            else:
                length += count - 1
                odd_found = True

        if odd_found:
            length += 1

        return length

cut-off-trees-for-golf-event.solution:
import heapq

class Solution(object):
    def cutOffTree(self, forest):
        if not forest or not forest[0]:
            return -1

        m, n = len(forest), len(forest[0])
        trees = sorted((h, i, j) for i, row in enumerate(forest) for j, h in enumerate(row) if h > 1)
        steps, start = 0, (0, 0)

        for height, i, j in trees:
            d = self.shortestDistance(forest, m, n, start, (i, j))
            if d < 0:
                return -1
            steps += d
            start = (i, j)
            forest[i][j] = 1

        return steps

    def shortestDistance(self, forest, m, n, start, dest):
        visited = [[False for _ in range(n)] for _ in range(m)]
        queue = [(0, start)]
        visited[start[0]][start[1]] = True

        while queue:
            dist, (x, y) = heapq.heappop(queue)

            if (x, y) == dest:
                return dist

            for r, c in ((x+1, y), (x-1, y), (x, y+1), (x, y-1)):
                if 0 <= r < m and 0 <= c < n and not visited[r][c] and forest[r][c] > 0:
                    heapq.heappush(queue, (dist + 1, (r, c)))
                    visited[r][c] = True

        return -1

count-of-range-sum.solution:
class Solution(object):
    def countRangeSum(self, nums, lower, upper):
        def mergeSort(lo, hi):
            if hi - lo <= 1:
                return 0

            mid = (lo + hi) // 2
            count = mergeSort(lo, mid) + mergeSort(mid, hi)
            i = j = mid

            for left in range(lo, mid):
                while i < hi and nums[i] - nums[left] < lower:
                    i += 1
                while j < hi and nums[j] - nums[left] <= upper:
                    j += 1
                count += j - i

            nums[lo:hi] = sorted(nums[lo:hi])

            return count

        return mergeSort(0, len(nums))

arranging-coins.solution:
class Solution(object):
    def arrangeCoins(self, n):
        """
        :type n: int
        :rtype: int
        """
        left, right = 0, n
        while left <= right:
            mid = (left + right) // 2
            coins_needed = (1 + mid) * mid // 2
            if coins_needed == n:
                return mid
            elif coins_needed < n:
                left = mid + 1
            else:
                right = mid - 1
        return right

