            if target == 0:
                result.append(path)
                return
            elif target < 0:
                return

            prev = -1
            for i in range(start, len(candidates)):
                if prev == candidates[i]:
                    continue
                if candidates[i] > target:
                    break
                backtrack(i + 1, path + [candidates[i]], target - candidates[i])
                prev = candidates[i]

        candidates.sort()
        result = []
        backtrack(0, [], target)
        return result

