class Solution(object):
    def removeInvalidParentheses(self, s):
        """
        :type s: str
        :rtype: List[str]
        """
        def is_valid(s):
            count = 0
            for c in s:
                if c == '(':
                    count += 1
                elif c == ')':
                    count -= 1
                    if count < 0:
                        return False
            return count == 0

        visited = set()
        queue = [s]
        result = []
        found = False

        while queue:
            s = queue.pop(0)
            if is_valid(s):
                result.append(s)
                found = True

            if found:
                continue

            for i in range(len(s)):
                if s[i] in ('(', ')'):
                    candidate = s[:i] + s[i+1:]
                    if candidate not in visited:
                        visited.add(candidate)
                        queue.append(candidate)

        return result

