        palindrome = [[False] * n for _ in range(n)]

        for i in range(n):
            dp[i] = i
            for j in range(i + 1):
                if s[i] == s[j] and (i - j <= 2 or palindrome[j + 1][i - 1]):
                    palindrome[j][i] = True
                    dp[i] = 0 if j == 0 else min(dp[i], dp[j - 1] + 1)

        return dp[n - 1]

