class Solution(object):
    def preimageSizeFZF(self, k):
        """
        :type k: int
        :rtype: int
        """
        def trailingZeroes(n):
            res = 0
            while n:
                n //= 5
                res += n
            return res

        left, right = 0, 5 * k
        while left < right:
            mid = (left + right) // 2
            if trailingZeroes(mid) < k:
                left = mid + 1
            else:
                right = mid
        return 5 if trailingZeroes(left) == k else 0

