class Solution(object):
    def containVirus(self, isInfected):
        m, n = len(isInfected), len(isInfected[0])
        dirs = [(0, 1), (0, -1), (1, 0), (-1, 0)]

        def dfs(r, c):
            if r < 0 or r >= m or c < 0 or c >= n or isInfected[r][c] == -1:
                return
            if isInfected[r][c] == 1:
                isInfected[r][c] = -1
                self.virus_cells.add((r, c))
                for dr, dc in dirs:
                    dfs(r + dr, c + dc)
            elif isInfected[r][c] == 0:
                self.fresh_cells.add((r, c))
                self.walls.add((r, c, r, c))
                for dr, dc in dirs:
                    dfs(r + dr, c + dc)

        def union_find():
            father = list(range(m * n))
            size = [1] * (m * n)

            def find(x):
                if father[x] != x:
                    father[x] = find(father[x])
                return father[x]

            def union(x, y):
                rootX, rootY = find(x), find(y)
                if rootX != rootY:
                    father[rootX] = rootY
                    size[rootY] += size[rootX]

            for cell in self.virus_cells:
                r, c = cell
                for dr, dc in dirs:
                    nr, nc = r + dr, c + dc
                    if nr < 0 or nr >= m or nc < 0 or nc >= n:
                        continue
                    if isInfected[nr][nc] == 1:
                        union(cell, (nr, nc))

            for cell in self.fresh_cells:
                r, c = cell
                father[find(cell)] = find((r, c))
                size[find((r, c))] = 0

            for wall in self.walls:
                r1, c1, r2, c2 = wall
                if find(wall) != find((r1, c1)) or find(wall) != find((r2, c2)):
                    union(wall, (r1, c1))
                    union(wall, (r2, c2))

        total_walls = 0
        while True:
            self.virus_cells = set()
            self.fresh_cells = set()
            self.walls = set()

            for r in range(m):
                for c in range(n):
                    if isInfected[r][c] == 1:
                        dfs(r, c)

            if not self.fresh_cells:
                break

            union_find()

            max_size = max(size[find(cell)] for cell in self.virus_cells)
            total_walls += sum(self.walls[i] for i in range(len(self.walls)) if size[find(self.walls[i])] == max_size)

            for cell in self.virus_cells:
                r, c = cell
                isInfected[r][c] = 1

        return total_walls

