class Solution:
    def longestIncreasingPath(self, matrix):
        if not matrix or not matrix[0]:
            return 0

        m, n = len(matrix), len(matrix[0])
        # dp[i][j] = length of longest increasing path starting at (i, j)
        dp = [[0]*n for _ in range(m)]

        def lip(matrix, dp, i, j):
            if dp[i][j] != 0:
                return dp[i][j]
            m, n = len(matrix), len(matrix[0])
            dirs = [(0,1), (1,0), (-1,0), (0,-1)]
            lip_len = 1
            for dx, dy in dirs:
                x, y = i + dx, j + dy
                if x < 0 or x >= m or y < 0 or y >= n or matrix[x][y] <= matrix[i][j]:
                    continue
                l = lip(matrix, dp, x, y)
                lip_len = max(lip_len, l+1)
            dp[i][j] = lip_len
            return lip_len

        lip_len = 0
        for i in range(m):
            for j in range(n):
                lip_len = max(lip_len, lip(matrix, dp, i, j))
        return lip_len

