falling-squares.solution:
class Solution(object):
    def fallingSquares(self, positions):
        """
        :type positions: List[List[int]]
        :rtype: List[int]
        """
        # Initialize the segment tree
        self.tree = [0] * 4 * 10**9
        self.pos = [0] * 10**4

        # Update function to update the segment tree
        def update(pos, val, index, left, right):
            if pos < left or pos > right:
                return
            if left == right:
                self.tree[index] = max(self.tree[index], val)
                return
            mid = (left + right) // 2
            update(pos, val, 2 * index + 1, left, mid)
            update(pos, val, 2 * index + 2, mid + 1, right)
            self.tree[index] = max(self.tree[2 * index + 1], self.tree[2 * index + 2])

        # Query function to get the maximum height in a range
        def query(left, right, index, l, r):
            if right < l or left > r:
                return 0
            if left <= l and r <= right:
                return self.tree[index]
            mid = (l + r) // 2
            return max(query(left, right, 2 * index + 1, l, mid), query(left, right, 2 * index + 2, mid + 1, r))

        # Main function to calculate the maximum height
        def falling(heights):
            max_height = 0
            ans = []
            for left, sideLength in heights:
                update(left, left + sideLength - 1, 0, 0, 10**9 - 1)
                ans.append(query(left, left + sideLength - 1, 0, 0, 10**9 - 1))
            return ans

        return falling(positions)

