class Solution(object):
    def maxSumSubmatrix(self, matrix, k):
        import bisect
        import math
        max_sum = -math.inf

        m, n = len(matrix), len(matrix[0])

        for l in range(n):
            sums = [0] * m
            for r in range(l, n):
                for i in range(m):
                    sums[i] += matrix[i][r]
                max_sum = max(max_sum, self.maxSumSubArray(sums, k))

        return max_sum

    def maxSumSubArray(self, nums, k):
        max_sum = -math.inf
        prefix_sum = 0
        prefix_sums = [0]
        for num in nums:
            prefix_sum += num
            idx = bisect.bisect_left(prefix_sums, prefix_sum - k)
            if idx != len(prefix_sums):
                max_sum = max(max_sum, prefix_sum - prefix_sums[idx])
            bisect.insort(prefix_sums, prefix_sum)
        return max_sum

