class Solution:
    def solve(self, board):
        if not board:
            return

        m, n = len(board), len(board[0])

        def capture(r, c):
            if board[r][c] == 'O':
                board[r][c] = 'T'
                if r > 0: capture(r-1, c)
                if r < m-1: capture(r+1, c)
                if c > 0: capture(r, c-1)
                if c < n-1: capture(r, c+1)

        # Capture all 'O's on the border
        for r in range(m):
            capture(r, 0)
            capture(r, n-1)

        for c in range(n):
            capture(0, c)
            capture(m-1, c)

        # Capture all remaining 'O's
        for r in range(m):
            for c in range(n):
                if board[r][c] == 'O':
                    board[r][c] = 'X'

        # Uncapture the surrouded 'O's
        for r in range(m):
            for c in range(n):
                if board[r][c] == 'T':
                    board[r][c] = 'O'

