import itertools

def judgePoint24(cards):
    if len(cards) == 1:
        return abs(cards[0] - 24) < 1e-6

    for p in itertools.permutations(cards):
        for d in map(lambda x: 1 if x == 0 else 1.0/x, p):
            if (d + p[0]) % d == 0 and judgePoint24(map(lambda x: x % d, p[1:])):
                return True
            if (d + p[1]) % d == 0 and judgePoint24(map(lambda x: x % d, p[:1] + p[2:])):
                return True
            if p[0] % d == 0 and judgePoint24(map(lambda x: x / d, p[1:])):
                return True
            if p[1] % d == 0 and judgePoint24(map(lambda x: x / d, p[:1] + p[2:])):
                return True
    return False

