            elif n < 100:
                return tens[n//10] + (" " + helper(n%10) if n%10 != 0 else "")
            elif n < 1000:
                return under_20[n//100] + " Hundred" + (" " + helper(n%100) if n%100 != 0 else "")
            else:
                for i, unit in enumerate(thousands[1:]):
                    if n < 1000**(i+2):
