class Solution(object):
    def findRedundantDirectedConnection(self, edges):
        """
        :type edges: List[List[int]]
        :rtype: List[int]
        """
        parent = list(range(len(edges) + 1))

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        last, can = None, []
        mp = {}
        for i, (x, y) in enumerate(edges):
            if y in mp:
                can.append([mp[y], y])
                can.append([x, y])
            else:
                mp[y] = x
        for x, y in edges:
            px, py = find(x), find(y)
            if px == py:
                if not can:
                    return [x, y]
                return can[0]
            parent[px] = py
        return can[1]

