class Solution(object):
    def cherryPickup(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: int
        """

        n = len(grid)
        dp = [[[-1 for _ in range(n)] for _ in range(n)] for _ in range(n)]

        def solve(r1, c1, c2):
            r2 = r1 + c1 - c2
            if min(r1, r2) < 0 or max(r1, r2) >= n or min(c1, c2) < 0 or max(c1, c2) >= n:
                return float('-inf')
            if grid[r1][c1] == -1 or grid[r2][c2] == -1:
                return float('-inf')
            if r1 == c1 == r2 == c2 == n - 1:
                return grid[r1][c1]
            if dp[r1][c1][c2] != -1:
                return dp[r1][c1][c2]

            cherries = 0
            if r1 == c1 == r2 == c2:
                cherries += grid[r1][c1]
            else:
                cherries += grid[r1][c1] + grid[r2][c2]

            up1 = solve(r1 - 1, c1, c2 - 1)
            up2 = solve(r1 - 1, c1, c2)
            up3 = solve(r1, c1 - 1, c2 - 1)
            up4 = solve(r1, c1 - 1, c2)

            cherries += max(up1, up2, up3, up4)
            dp[r1][c1][c2] = cherries
            return cherries

        cherries = solve(0, 0, n - 1)
        return max(cherries, 0)

