            mod = 10**9 + 7
            A = [1, 2, 4, 7]  # A[i] = A[i-1] * 2 % mod
            P = [1, 2, 4, 7]  # P[i] = A[i-1] * 2 % mod
            L = [1, 2, 4, 7]  # L[i] = A[i-1] * 2 % mod
            for i in range(3, n+1):
                A.append((A[-1] * 2 % mod + mod - 1) % mod)
                P.append((P[-1] * 2 % mod + mod - 1) % mod)
                L.append((L[-1] * 2 % mod + mod - 1) % mod)
                if i > 3:
                    L[i-1] = (L[i-1] - L[i-4] + mod) % mod
                if i > 4:
                    P[i-1] = (P[i-1] - P[i-5] + mod) % mod
            return (A[n-1] * 2 % mod + mod - 1 - A[n-2] - P[n-1] - L[n-1]) % mod

