class Solution(object):
    def splitArray(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: int
        """

        def can_split(largest_sum):
            subarray_count = 1
            current_sum = 0
            for num in nums:
                current_sum += num
                if current_sum > largest_sum:
                    subarray_count += 1
                    current_sum = num
            return subarray_count <= k

        low, high = max(nums), sum(nums)
        while low < high:
            mid = (low + high) // 2
            if can_split(mid):
                high = mid
            else:
                low = mid + 1
        return low

