class Solution(object):
    def letterCombinations(self, digits):
        """
        :type digits: str
        :rtype: List[str]
        """
        if len(digits) == 0:
            return []

        self.result = []
        self.digits = digits
        self.lookup = {'2': 'abc', '3': 'def', '4': 'ghi', '5': 'jkl', 
                       '6': 'mno', '7': 'pqrs', '8': 'tuv', '9': 'wxyz'}

        self.backtrack('', 0)
        return self.result

    def backtrack(self, so_far, idx):
        if len(so_far) == len(self.digits):
            self.result.append(so_far)
            return

        for i in self.lookup[self.digits[idx]]:
            self.backtrack(so_far + i, idx + 1)

