        """
        :type n: str
        :rtype: str
        """
        if n == "1": return "0"
        if n == "10": return "9"

        l = len(n)
        candidates = [10**(l-1) - 1, 10**l + 1]
        selfPrefix = int(n[:(l+1)//2])

        for x in range(selfPrefix, selfPrefix-1):
            candidates.append(int(str(x) + (str(x))[::-1]))

        ans = None
        selfNumber = int(n)

        for candidate in candidates:
            if candidate != selfNumber:
                if ans is None or abs(candidate - selfNumber) < abs(ans - selfNumber) or abs(candidate - selfNumber) == abs(ans - selfNumber) and candidate < ans:
                    ans = candidate
        return str(ans)

