        dp = {stone: set() for stone in stones}
        dp[0].add(1)

        for stone in stones:
            for step in dp[stone]:
                if step > 0 and stone + step in dp:
                    dp[stone + step].add(step)
                    if step - 1 > 0: dp[stone + step].add(step - 1)
                    if step + 1 > 0: dp[stone + step].add(step + 1)

        return bool(dp[stones[-1]])

