        total_length = word_length * len(words)
        word_count = Counter(words)
        result = []

        for i in range(len(s) - total_length + 1):
            window = [s[j:j+word_length] for j in range(i, i+total_length, word_length)]
            if Counter(window) == word_count:
                result.append(i)

