class Solution(object):
    def minStickers(self, stickers, target):
        from collections import defaultdict

        # create a dictionary to store the frequency of each character in each sticker
        dic = defaultdict(int)
        for i in range(len(stickers)):
            for char in stickers[i]:
                dic[(i, char)] += 1

        # create a memoization dictionary
        memo = {}

        def dp(t):
            if t in memo: return memo[t]
            if sum([c in t for c in target]) == len(target):
                return 0

            ans = float('inf')
            for s in dic:
                if dic[s] == 0: continue
                if t == "": t = s[1]
                elif s[0] not in t: continue
                else:
                    t = t.replace(s[0], "", dic[s])
                tmp = dp(t)
                if tmp != -1: ans = min(ans, 1 + tmp)
            memo[t] = -1 if ans == float('inf') else ans
            return memo[t]

        return dp(target)

