def strange_printer(s):
    cache = {}

    def dfs(start, end):
        if start > end:
            return 0
        if (start, end) in cache:
            return cache[(start, end)]

        min_turns = dfs(start + 1, end) + 1
        for i in range(start + 1, end + 1):
            if s[i] == s[start]:
                min_turns = min(min_turns, dfs(start + 1, i - 1) + dfs(i, end))
        cache[(start, end)] = min_turns
        return min_turns

    return dfs(0, len(s) - 1)

