class Solution(object):
    def isRectangleCover(self, rectangles):
        """
        :type rectangles: List[List[int]]
        :rtype: bool
        """
        area, x, y, x1, y1 = 0, rectangles[0][0], rectangles[0][1], rectangles[0][2], rectangles[0][3]
        cnt = collections.defaultdict(int)
        for r in rectangles:
            x, y, x1, y1 = min(x, r[0]), min(y, r[1]), max(x1, r[2]), max(y1, r[3])
            area += (r[2] - r[0]) * (r[3] - r[1])
            for point in [(r[0], r[1]), (r[0], r[3]), (r[2], r[3]), (r[2], r[1])]:
                cnt[point] += 1
        if area != (x1 - x) * (y1 - y):
            return False
        if any(cnt[(x, y)] != 1 and cnt[(x, y)] != 3 or cnt[(x1, y)] != 1 and cnt[(x1, y)] != 3 or cnt[(x, y1)] != 1 and cnt[(x, y1)] != 3 or cnt[(x1, y1)] != 1 and cnt[(x1, y1)] != 3 for x, y in [(x, y), (x1, y), (x, y1), (x1, y1)]):
            return False
        if any(cnt[p] != 4 and cnt[p] != 2 for p in cnt if p not in [(x, y), (x, y1), (x1, y), (x1, y1)]):
            return False
        return True

