    def countSmaller(self, nums):
        """
        :type nums: List[int]
        :rtype: List[int]
        """
        def merge_sort(enum):
            half = len(enum) // 2
            if half:
                left, right = merge_sort(enum[:half]), merge_sort(enum[half:])
                for i in range(len(enum))[::-1]:
                    if not right or left and left[-1][1] > right[-1][1]:
                        smaller[left[-1][0]] += len(right)
                        enum[i] = left.pop()
                    else:
                        enum[i] = right.pop()
        smaller = [0] * len(nums)
        merge_sort(list(enumerate(nums)))
        return smaller

number-of-atoms.solution:
class Solution:
    def countOfAtoms(self, formula: str) -> str:
        def get_atom_count(i):
            counts = collections.defaultdict(int)
            while i < len(formula):
                if formula[i] == ')':
                    i += 1
                    cnt = 1
                    while i < len(formula) and formula[i].isdigit():
                        cnt = cnt * 10 + int(formula[i])
                        i += 1
                    counts = multiply(counts, cnt)
                elif formula[i] == '(':
                    i += 1
                    sub_counts = get_atom_count(i)
                    counts = add(counts, sub_counts)
                else:
                    j = i + 1
                    while j < len(formula) and formula[j].islower():
                        j += 1
                    atom = formula[i:j]
                    cnt = 1
                    while j < len(formula) and formula[j].isdigit():
                        cnt = cnt * 10 + int(formula[j])
                        j += 1
                    counts[atom] += cnt
                    i = j
            return counts

        def multiply(counts1, counts2):
            counts = collections.defaultdict(int)
            for atom, cnt in counts1.items():
                counts[atom] += cnt * counts2[atom]
            return counts

        def add(counts1, counts2):
            counts = collections.defaultdict(int)
            for atom, cnt in counts1.items():
                counts[atom] += cnt
            for atom, cnt in counts2.items():
                counts[atom] += cnt
            return counts

        counts = get_atom_count(0)
        res = []
        for atom in sorted(counts.keys()):
            res.append(atom)
            if counts[atom] > 1:
                res.append(str(counts[atom]))
        return ''.join(res)

