            if left:         generate(parens + '(', left-1, right, parens_list)
            if right > left: generate(parens + ')', left, right-1, parens_list)
            if not right:    parens_list.append(parens)

        parens_list = []
        generate('', n, n, parens_list)
        return parens_list

