class Solution(object):
    def setZeroes(self, matrix):
        """
        :type matrix: List[List[int]]
        :rtype: None Do not return anything, modify matrix in-place instead.
        """
        # Determine the number of rows and columns
        m, n = len(matrix), len(matrix[0])

        # Use the first row and first column to mark if there is a zero in the rest of the matrix
        first_row_has_zero = any(matrix[0][j] == 0 for j in range(n))
        first_col_has_zero = any(matrix[i][0] == 0 for i in range(m))

        # Scan the rest of the matrix to mark the zeros
        for i in range(1, m):
            for j in range(1, n):
                if matrix[i][j] == 0:
                    matrix[i][0] = matrix[0][j] = 0

        # Set zeros based on the marks
        for i in range(1, m):
            for j in range(1, n):
                if matrix[i][0] == 0 or matrix[0][j] == 0:
                    matrix[i][j] = 0

        # Set the first row and first column to zero if needed
        if first_row_has_zero:
            for j in range(n):
                matrix[0][j] = 0

        if first_col_has_zero:
            for i in range(m):
                matrix[i][0] = 0

super-washing-machines.solution:
def findMinMoves(machines):
    total = sum(machines)
    if total % len(machines) != 0:
        return -1
    avg = total // len(machines)
    left = [0] * len(machines)
    for i in range(1, len(machines)):
        left[i] = left[i-1] + avg - machines[i-1]
    right = [0] * len(machines)
    for i in range(len(machines)-2, -1, -1):
        right[i] = right[i+1] + avg - machines[i+1]
    return max(max(left), max(right))

