class Solution(object):
    def findKthNumber(self, m, n, k):
        """
        :type m: int
        :type n: int
        :type k: int
        :rtype: int
        """
        low, high = 1, m * n + 1

        while low < high:
            mid = (low + high) // 2
            count = mid // n * n
            for i in range(mid // n + 1, m + 1):
                count += mid // i

            if count >= k:
                high = mid
            else:
                low = mid + 1

        return low

