        rows = [set() for _ in range(9)]
        cols = [set() for _ in range(9)]
        boxes = [[set() for _ in range(3)] for _ in range(3)]

        for r in range(9):
            for c in range(9):
                val = board[r][c]
                if val == ".": continue

                if val in rows[r] or val in cols[c] or val in boxes[r//3][c//3]:
