    def findAllConcatenatedWordsInADict(self, words):
        """
        :type words: List[str]
        :rtype: List[str]
        """
        words = sorted(words, key=len)
        res = []
        wordset = set([''])
        for word in words:
            if self.wordBreak(word, wordset):
                res.append(word)
            wordset.add(word)
        return res

    def wordBreak(self, s, wordset):
        if s in wordset:
            return True
        for i in range(1, len(s)):
            prefix, suffix = s[:i], s[i:]
            if prefix in wordset and self.wordBreak(suffix, wordset):
                return True
        return False

